import{_ as e,o as a,c as i,ae as t}from"./chunks/framework.BMBGeRFM.js";const k=JSON.parse('{"title":"The Rulez","description":"","frontmatter":{},"headers":[],"relativePath":"styles/rulez/index.md","filePath":"styles/rulez/index.md"}'),n={name:"styles/rulez/index.md"};function l(r,s,o,p,h,d){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="the-rulez" tabindex="-1">The Rulez <a class="header-anchor" href="#the-rulez" aria-label="Permalink to &quot;The Rulez&quot;">​</a></h1><p>Since Farben creates its own &quot;TOML-like parser,&quot; while not actually being a TOML parser at all, it has some rulesets different than TOML. This is the reason why the <code>.frb</code> part of the extension exists, it&#39;s to signal that &quot;I agree that this file will be following the Farben-TOML ruleset,&quot; and will error on breaking it.</p><p>The following is the serious spec:</p><h1 id="farbentoml-2026-04" tabindex="-1">FarbenTOML/2026-04 <a class="header-anchor" href="#farbentoml-2026-04" aria-label="Permalink to &quot;FarbenTOML/2026-04&quot;">​</a></h1><p><strong>Full name:</strong> FarbenTOML/2026-04</p><p><strong>Short aliases:</strong> FRB-TOML-2026-04, FRB-2026-04, Farben-TOML-2026-04</p><p><strong>File extension:</strong> <code>.frb.toml</code></p><p><strong>Status:</strong> Active, subject to breaking changes as the parser evolves</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>FarbenTOML is a strict subset of TOML syntax with additional constraints imposed by Farben&#39;s config parser. It is not a TOML parser and does not aim for TOML compliance. The <code>.frb</code> segment of the file extension signals that the file follows this ruleset rather than standard TOML. A file that passes a TOML parser may still be invalid FarbenTOML, and a conforming FarbenTOML file may not be valid in all TOML parsers.</p><p>This document defines the FarbenTOML/2026-04 ruleset. All <code>.frb.toml</code> files are expected to conform to it.</p><h2 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h2><h3 id="r1-string-only-values" tabindex="-1">R1: String-only values <a class="header-anchor" href="#r1-string-only-values" aria-label="Permalink to &quot;R1: String-only values&quot;">​</a></h3><p>Only string values are permitted. Every value must be wrapped in double quotes. No other TOML value types are accepted, including booleans, integers, floats, arrays, and inline tables.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Valid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Invalid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = b</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">old red</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">42</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = { fg = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;red&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;red&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>Rationale:</strong> The parser reads values as raw strings and passes them directly to the Farben rendering pipeline. Non-string types have no defined meaning in this context.</p><h3 id="r2-style-values-are-stored-without-brackets" tabindex="-1">R2: Style values are stored without brackets <a class="header-anchor" href="#r2-style-values-are-stored-without-brackets" aria-label="Permalink to &quot;R2: Style values are stored without brackets&quot;">​</a></h3><p>Under <code>[styles]</code>, values are stored as plain markup strings without the surrounding <code>[...]</code> brackets. The brackets are added by the consumer.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">styles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span></code></pre></div><p>This is stored as <code>&quot;bold red&quot;</code>, not <code>&quot;[bold red]&quot;</code>. When <code>farben-build</code> processes this entry, it wraps the value in brackets before passing it to <code>farben::Style::parse()</code>.</p><h4 id="exception-direct-use-of-farben-build-core-parse" tabindex="-1">Exception: direct use of <code>farben_build::core::parse()</code> <a class="header-anchor" href="#exception-direct-use-of-farben-build-core-parse" aria-label="Permalink to &quot;Exception: direct use of \`farben_build::core::parse()\`&quot;">​</a></h4><p>When calling <code>farben_build::core::parse()</code> directly (for example, to power your own application&#39;s theming system), the brackets are not added automatically. In this case, values must include the brackets explicitly:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">styles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[bold red]&quot;</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>It is generally safer to always write values with explicit brackets and adjust the consumer accordingly. This avoids ambiguity when switching between <code>farben-build</code> codegen and direct <code>core::parse()</code> usage.</p></div><h3 id="r3-no-inline-comments" tabindex="-1">R3: No inline comments <a class="header-anchor" href="#r3-no-inline-comments" aria-label="Permalink to &quot;R3: No inline comments&quot;">​</a></h3><p>Comments must occupy their own line and must start with <code>#</code> as the first character. The parser uses a <code>line.starts_with(&#39;#&#39;)</code> check, so any <code>#</code> that appears after a value is treated as part of the value string, not as a comment delimiter.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Valid</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># This is a comment</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Invalid: the comment text becomes part of the value</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # applies to errors</span></span></code></pre></div><p>Inline comments produce a parse error. The # appearing after a value causes the parser to reject the line entirely. Comments must be on their own line with # as the first character.</p><h3 id="r4-only-styles-and-prefixes-sections-are-valid" tabindex="-1">R4: Only <code>[styles]</code> and <code>[prefixes]</code> sections are valid <a class="header-anchor" href="#r4-only-styles-and-prefixes-sections-are-valid" aria-label="Permalink to &quot;R4: Only \`[styles]\` and \`[prefixes]\` sections are valid&quot;">​</a></h3><p>The only permitted section headers are <code>[styles]</code> and <code>[prefixes]</code>, and their namespaced variants (e.g. <code>[styles.myapp]</code> if supported by a given consumer). Any other section name causes a parse error.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Valid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">styles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">prefixes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;!! &quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Invalid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">colors</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">red = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">meta</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">author = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;razkar&quot;</span></span></code></pre></div><h3 id="r5-keys-must-not-be-quoted" tabindex="-1">R5: Keys must not be quoted <a class="header-anchor" href="#r5-keys-must-not-be-quoted" aria-label="Permalink to &quot;R5: Keys must not be quoted&quot;">​</a></h3><p>Key identifiers must be written bare. The parser trims whitespace around keys but does not strip surrounding quotes. A quoted key is treated as a literal string including the quote characters, which will not match any valid identifier.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Valid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">my::namespace.key = &quot;yellow&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Invalid</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;error&quot; = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;my::namespace.key&quot; = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;yellow&quot;</span></span></code></pre></div><p>Keys may contain characters that are not valid TOML bare keys (such as <code>:</code>). This is intentional and specific to FarbenTOML.</p><h3 id="r6-duplicate-keys-are-a-compile-time-error" tabindex="-1">R6: Duplicate keys are a compile-time error <a class="header-anchor" href="#r6-duplicate-keys-are-a-compile-time-error" aria-label="Permalink to &quot;R6: Duplicate keys are a compile-time error&quot;">​</a></h3><p>The parser itself does not reject duplicate keys at parse time, but <code>farben-build</code> panics at compile time if the same key appears more than once within a section. The last value does not silently win as it would in some TOML implementations.</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Causes a compile-time panic via farben-build</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">styles</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bold red&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">error = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;red bold&quot;</span></span></code></pre></div><p>If you are using <code>core::parse()</code> directly without <code>farben-build</code>, duplicate key handling is the caller&#39;s responsibility. The returned data structure reflects the last-seen value; no error is raised.</p><h2 id="conformance" tabindex="-1">Conformance <a class="header-anchor" href="#conformance" aria-label="Permalink to &quot;Conformance&quot;">​</a></h2><p>A file conforms to FarbenTOML/2026-04 if and only if it satisfies all six rules above. Conformance is context-dependent for R2: the bracket convention depends on whether the file is consumed by <code>farben-build</code> codegen or by a direct <code>core::parse()</code> caller.</p><h2 id="stability" tabindex="-1">Stability <a class="header-anchor" href="#stability" aria-label="Permalink to &quot;Stability&quot;">​</a></h2><p>FarbenTOML/2026-04 is the active revision as of April 2026. The ruleset is expected to evolve as the parser becomes more capable. Future revisions may relax or replace individual rules, and will be issued under a new revision identifier. Files conforming to an older revision are not guaranteed to conform to future ones.</p>`,43)])])}const u=e(n,[["render",l]]);export{k as __pageData,u as default};
